using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(b =>
        {
            // Fix 1: Restore old discriminator property name (was renamed to "$type" in EF 9)
            b.HasDiscriminator<string>("Discriminator");

            // Fix 2: Keep discriminator in the JSON id (EF 9 removed it; old format: "Blog|8")
            b.HasDiscriminatorInJsonId();

            // Fix 3: Keep the shadow __id property (EF 9 maps key directly to JSON id)
            b.HasShadowId();
        });

        // Fix 6: Removed HasIndex — EF 9 Cosmos now throws instead of silently ignoring it
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

